class DSU(val n: Int) {
  val parent: Array[Int] = Array.fill(n)(0)
  val rank: Array[Int] = Array.fill(n)(1)

  def find(x: Int): Int = {
    if (parent(x) != x) {
      parent(x) = find(parent(x))
    }
    parent(x)
  }

  def union(x: Int, y: Int): Unit = {
    val xRoot = find(x)
    val yRoot = find(y)
    if (xRoot == yRoot) return
    if (rank(xRoot) < rank(yRoot)) {
      parent(xRoot) = yRoot
    } else {
      parent(yRoot) = xRoot
      if (rank(xRoot) == rank(yRoot)) {
        rank(xRoot) += 1
      }
    }
  }
}

def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
  val sortedEdges = edges.sortWith((a, b) => a(2) < b(2))
  val maxW = edges.map(_.apply(2)).max
  var low = 0L
  var high = maxW
  var answer = maxW

  while (low <= high) {
    val mid = (low + high) / 2
    val dsu = new DSU(n.toInt)
    for (edge <- sortedEdges) {
      val u = edge(0).toInt
      val v = edge(1).toInt
