    var components = 0
    for (i <- 0 until n.toInt) {
      if (dsu.find(i) == i) {
        components += 1
      }
    }
    if (components <= k) {
      answer = mid
      high = mid - 1
    } else {
      low = mid + 1
    }
  }
  answer
}
