class DSU(val size: Int) {
  private val parent: Array[Int] = (0 until size).map(i => i).toArray
  private val rank: Array[Int] = Array.fill(size)(1)

  def find(x: Int): Int = {
    if (parent(x) != x) {
      parent(x) = find(parent(x))
    }
    parent(x)
  }

  def union(x: Int, y: Int): Unit = {
    val xRoot = find(x)
    val yRoot = find(y)
    if (xRoot == yRoot) return
    if (rank(xRoot) < rank(yRoot)) {
      parent(xRoot) = yRoot
    } else {
      parent(yRoot) = xRoot
      if (rank(xRoot) == rank(yRoot)) {
        rank(xRoot) += 1
      }
    }
  }
}

def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
  val sortedEdges = edges.sortWith { a, b => a(2) < b(2) }
  val maxW = sortedEdges.last(2)
  var low = 0L
  var high = maxW
  var answer = maxW
  while (low <= high) {
    val mid = (low + high) / 2
    val dsu = new DSU(n.toInt)
    for (edge <- sortedEdges) {
      if (edge(2) <= mid) {
        dsu.union(edge(0).toInt, edge(1).toInt)
      }
    }
    var components = 0
    for (i <- 0 until n.toInt) {
      if (dsu.find(i) == i) components += 1
    }
    if (components <= k) {
      answer = mid
      high = mid - 1
    } else {
      low = mid + 1
    }
  }
  answer
}
